const msg = ($json.message && $json.message.text) ? $json.message.text : '';
const chatId = $json.message ? $json.message.chat.id : ($json.chat ? $json.chat.id : null);
const isCommand = msg.startsWith('/');
let command = 'chat';
if (msg.startsWith('/bookings')) command = 'bookings';
else if (msg.startsWith('/review')) command = 'review';
else if (msg.startsWith('/post')) command = 'post';
else if (msg.startsWith('/help') || msg.startsWith('/start')) command = 'help';
return [{ json: { chatId, rawText: msg, command, cleaned: msg.replace(/^\/\w+\s*/, '') } }];

const rows = $json.all ? $json.all() : ($items ? $items() : []);
const data = Array.isArray(rows) ? rows.map(r => r.json || r) : (rows || []);
if (!data.length) return [{ json: { text: 'No recent bookings found.' } }];
const lines = data.map(r => `• ${r.name} | ${r.vehicle || '?'} | ${r.pickup} → ${r.dropoff}
  ${r.time} | ☎ ${r.phone}`).join('

');
return [{ json: { text: '📋 Recent Bookings (last 10):

' + lines } }];

return [{ json: { text: '⭐ Review Requests:

Use the review-requests workflow or send the GBP review link after each ride.

Tip: avalimo.net/book drives most new clients. Track reviews in Google Business Profile → Reviews.' } }];

const post = $json.choices ? $json.choices[0].message.content : ($json.text || '');
return [{ json: { text: '📣 LinkedIn draft (review & paste to LinkedIn):

' + post + '

— AvaLimo | (832) 567-8050 | avalimo.net' } }];
